const text = ($json.text || '').trim();
return [{ json: {
  raw_text: text,
  channel: $json.channel,
  message_ts: $json.ts,
  thread_ts: $json.thread_ts || $json.ts,
  user: $json.user,
  slack_event: $json,
} }];

const body = {
  model: 'anthropic/claude-haiku-4.5',
  temperature: 0,
  messages: [
    {
      role: 'system',
      content: [
        'You route requests for a UK boutique M&A finance research analyst.',
        'Return raw JSON only.',
        'Use intent values: research, pitch, brief, unknown.',
        'Extract only what is present or safely inferable from the message text.',
        'Do not claim to know Companies House numbers or websites yet.',
        'For pitch requests, capture the company_name.',
        'For brief requests, capture the sector.',
        'Ensure sector, ticker  and company_url are derived on your own if not provided'
      ].join(' '),
    },
    {
      role: 'user',
      content: $json.raw_text,
    },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'finance_research_intent',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          intent: { type: 'string', enum: ['research', 'pitch', 'brief', 'unknown'] },
          company_name: { type: ['string', 'null'] },
          sector: { type: ['string', 'null'] },
          ticker: { type: ['string', 'null'] },
          company_url: { type: ['string', 'null'] },
          confidence: { type: ['number', 'null'] },
          reasoning_note: { type: ['string', 'null'] }
        },
        required: ['intent', 'company_name', 'sector', 'ticker', 'company_url', 'confidence', 'reasoning_note']
      }
    }
  }
};
return [{ json: { ...$json, openrouter_body: body } }];

function parseJson(text) {
  if (!text) return {};
  const cleaned = String(text).trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate);
}
const content = $json.choices?.[0]?.message?.content || '{}';
const parsed = parseJson(content);
return [{ json: {
  raw_text: $('Prepare Slack Context').item.json.raw_text,
  channel: $('Prepare Slack Context').item.json.channel,
  thread_ts: $('Prepare Slack Context').item.json.thread_ts,
  user: $('Prepare Slack Context').item.json.user,
  intent: parsed.intent || 'unknown',
  company_name: parsed.company_name || '',
  sector: parsed.sector || '',
  ticker: parsed.ticker || '',
  company_url: parsed.company_url || '',
  confidence: parsed.confidence ?? null,
  reasoning_note: parsed.reasoning_note || '',
} }];

return [{ json: {
  channel: $json.channel,
  thread_ts: $json.thread_ts,
  reply_text: 'I could not route that request. Try one of: `Research Monzo, fintech`, `Prepare pitch for Monzo`, or `Industry briefing UK fintech`.'
} }];

return [{ json: {
  channel: $json.channel,
  thread_ts: $json.thread_ts,
  reply_text: 'Research requests need a company name. Example: `Research Revolut, fintech`.'
} }];

const input = $('Has Research Inputs?').item.json;
const target = (input.company_name || '').toLowerCase().trim();
const items = Array.isArray($json.items) ? $json.items : [];
const ranked = items
  .filter((item) => item.company_number)
  .map((item) => {
    const title = String(item.title || '').toLowerCase();
    let score = 0;
    if (item.company_status === 'active') score += 5;
    if (title === target) score += 20;
    if (title.startsWith(target)) score += 10;
    if (title.includes(target)) score += 5;
    if (item.address_snippet && String(item.address_snippet).toLowerCase().includes('united kingdom')) score += 1;
    return { item, score };
  })
  .sort((a, b) => b.score - a.score);
const best = ranked[0]?.item || null;
return [{ json: {
  ...input,
  match_found: Boolean(best),
  company_number: best?.company_number || '',
  matched_title: best?.title || '',
  matched_company_status: best?.company_status || '',
  matched_address: best?.address_snippet || '',
} }];

return [{ json: {
  channel: $json.channel,
  thread_ts: $json.thread_ts,
  reply_text: `Companies House could not find a reliable UK company match for *${$json.company_name}*. Check spelling or provide the registered company name.`
} }];

const routed = $('Pick Best Company Match').item.json;
const bundle = {
  channel: routed.channel,
  thread_ts: routed.thread_ts,
  raw_text: routed.raw_text,
  company_name: routed.company_name,
  sector: routed.sector,
  ticker: routed.ticker,
  company_url: routed.company_url,
  company_number: routed.company_number,
  matched_title: routed.matched_title,
  sources: {},
  warnings: [],
};
for (const item of $input.all()) {
  const source = item.json.source;
  if (source) bundle.sources[source] = item.json.data;
}
if (bundle.sources.alphavantage?.skipped) bundle.warnings.push(bundle.sources.alphavantage.reason);
const websiteHit = Array.isArray(bundle.sources.website?.data) ? bundle.sources.website.data[0] : bundle.sources.website?.data?.[0];
const websiteUrl = websiteHit?.url || websiteHit?.metadata?.sourceURL || bundle.company_url || '';
const marketCapRaw = bundle.sources.alphavantage?.MarketCapitalization || bundle.sources.alphavantage?.['Global Quote']?.['05. price'] || '';
bundle.market_cap = marketCapRaw && marketCapRaw !== 'None' ? marketCapRaw : '';
bundle.website_url = websiteUrl;
return [{ json: bundle }];

const body = {
  model: 'anthropic/claude-sonnet-4.5',
  temperature: 0.2,
  messages: [
    {
      role: 'system',
      content: [
        'You are a junior finance research analyst for a UK boutique M&A advisory.',
        'Use only the supplied source data.',
        'If a field is missing, say it is unavailable rather than inventing it.',
        'Return raw JSON only.'
      ].join(' '),
    },
    {
      role: 'user',
      content: `Create a company research pack for ${$json.company_name} in sector ${$json.sector || 'unknown'} using this source bundle:\n${JSON.stringify($json)}`,
    },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'finance_research_output',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          profile_markdown: { type: 'string' },
          slack_summary: { type: 'string' },
          market_cap_summary: { type: 'string' },
          risks_summary: { type: 'string' }
        },
        required: ['profile_markdown', 'slack_summary', 'market_cap_summary', 'risks_summary']
      }
    }
  }
};
return [{ json: { ...$json, openrouter_body: body } }];

function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate);
}
const content = $json.choices?.[0]?.message?.content || '{}';
const parsed = parseJson(content);
return [{ json: {
  ...$('Build Research Prompt').item.json,
  profile_markdown: parsed.profile_markdown,
  slack_summary: parsed.slack_summary,
  market_cap_summary: parsed.market_cap_summary,
  risks_summary: parsed.risks_summary,
} }];

