const docUrl = `https://docs.google.com/document/d/${$('Create Profile Doc').first().json.id}/edit`;
return [{ json: {
  channel: $('Parse Research Output').first().json.channel,
  thread_ts: $('Parse Research Output').first().json.thread_ts,
  reply_text: `Research complete for *${$('Parse Research Output').first().json.company_name}*\n\n${$('Parse Research Output').first().json.slack_summary}\n\nProfile doc: ${docUrl}`
} }];

return [{ json: {
  channel: $json.channel,
  thread_ts: $json.thread_ts,
  reply_text: 'Pitch requests need a company name. Example: `Prepare pitch for Revolut`.'
} }];

return [{ json: {
  channel: $('Parse Intent').item.json.channel,
  thread_ts: $('Parse Intent').item.json.thread_ts,
  reply_text: `No stored research exists for *${$('Parse Intent').item.json.company_name}*. Run a research request first.`
} }];

const company = $('Load Company Record').item.json;
const memory = $('Load Research Memory').item.json.content_text;
const body = {
  model: 'anthropic/claude-haiku-4.5',
  temperature: 0.2,
  messages: [
    {
      role: 'system',
      content: [
        'You prepare pitch materials for a boutique corporate finance team.',
        'Free-tier mode only: do not invent deal comps, valuation multiples, or proprietary transaction data.',
        'If comps are unavailable, say so plainly.',
        'All slide content must be short, presentation-ready, and formatted as concise bullet points.',
        'Do not write narrative paragraphs for slide fields.',
        'For profile_summary, financials, opportunity_summary, and comps_note, return 3 to 5 bullets max per field.',
        'Keep each bullet to one short line where possible.',
        'If the template contains charts, leave chart content implied by the bullets rather than describing charts in prose.',
        'Return raw JSON only.'
      ].join(' '),
    },
    {
      role: 'user',
      content: `Create pitch materials for ${company.company_name}. Stored research:\n${memory}\n\nImportant: the deck is copied into a slide template. Keep the slide text compact so it fits neatly into text boxes. Use bullet points, not paragraphs.` ,
    },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'finance_pitch_output',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          profile_summary: { type: 'string' },
          financials: { type: 'string' },
          opportunity_summary: { type: 'string' },
          comps_note: { type: 'string' },
          press_release_markdown: { type: 'string' },
          slack_summary: { type: 'string' }
        },
        required: ['profile_summary', 'financials', 'opportunity_summary', 'comps_note', 'press_release_markdown', 'slack_summary']
      }
    }
  }
};
return [{ json: {
  channel: $('Parse Intent').item.json.channel,
  thread_ts: $('Parse Intent').item.json.thread_ts,
  company_name: company.company_name,
  sector: company.sector,
  openrouter_body: body,
} }];

function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^```json\s*/i, '').replace(/^```/, '').replace(/```$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate);
}
const content = $json.choices?.[0]?.message?.content || '{}';
const parsed = parseJson(content);
return [{ json: {
  ...$('Build Pitch Prompt').item.json,
  profile_summary: parsed.profile_summary,
  financials: parsed.financials,
  opportunity_summary: parsed.opportunity_summary,
  comps_note: parsed.comps_note,
  press_release_markdown: parsed.press_release_markdown,
  slack_summary: parsed.slack_summary,
} }];

const deckUrl = `https://docs.google.com/presentation/d/${$('Copy Slides Template').first().json.id}/edit`;
const docUrl = `https://docs.google.com/document/d/${$('Create Press Release Doc').first().json.id}/edit`;
return [{ json: {
  channel: $('Parse Pitch Output').first().json.channel,
  thread_ts: $('Parse Pitch Output').first().json.thread_ts,
  reply_text: `Pitch materials ready for *${$('Parse Pitch Output').first().json.company_name}*\n\n${$('Parse Pitch Output').first().json.slack_summary}\n\nPitch deck: ${deckUrl}\nPress release draft: ${docUrl}`
} }];

return [{ json: {
  channel: $json.channel,
  thread_ts: $json.thread_ts,
  reply_text: 'Industry briefings need a sector. Example: `Industry briefing UK fintech`.'
} }];

const routed = $('Parse Intent').item.json;
const bundle = {
  channel: routed.channel,
  thread_ts: routed.thread_ts,
  sector: routed.sector,
  raw_text: routed.raw_text,
  sources: {},
};
for (const item of $input.all()) {
  if (item.json.source) bundle.sources[item.json.source] = item.json.data;
}
return [{ json: bundle }];

const body = {
  model: 'anthropic/claude-haiku-4.5',
  temperature: 0.2,
  messages: [
    {
      role: 'system',
      content: [
        'You write concise UK corporate finance industry briefings.',
        'Use only the supplied inputs.',
        'ONS data is macro M&A context, not sector deal comps.',
        'Return raw JSON only.'
      ].join(' '),
    },
    {
      role: 'user',
      content: `Create a one-page industry briefing for ${$json.sector}. Source bundle:\n${JSON.stringify($json)}`,
    },
  ],
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'finance_brief_output',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        properties: {
          brief_markdown: { type: 'string' },
          slack_summary: { type: 'string' }
        },
        required: ['brief_markdown', 'slack_summary']
      }
    }
  }
};
return [{ json: { ...$json, openrouter_body: body } }];

